"use client";

import { useEffect, useState } from "react";
import { Budget } from "@/types";
import { getBudgets, createBudget, updateBudget } from "@/lib/budgets";
import { getSpendAnalytics } from "@/lib/analytics";
import { CURRENCIES, formatCurrency } from "@/lib/currencies";

export default function BudgetsPage() {
    const [budgets, setBudgets] = useState<Budget[]>([]);
    const [spendByDept, setSpendByDept] = useState<Record<string, number>>({});
    const [loading, setLoading] = useState(true);
    const [showModal, setShowModal] = useState(false);
    const [editingId, setEditingId] = useState<string | null>(null);

    const [formData, setFormData] = useState({
        department: 'General',
        amount: 0,
        currency: 'USD',
        fiscalYear: '2026'
    });

    const fetchData = async () => {
        setLoading(true);
        const [budgetData, analyticsData] = await Promise.all([
            getBudgets(),
            getSpendAnalytics()
        ]);
        setBudgets(budgetData);
        setSpendByDept(analyticsData.spendByDepartment);
        setLoading(false);
    };

    useEffect(() => {
        fetchData();
    }, []);

    const handleEdit = (budget: Budget) => {
        setEditingId(budget.id!);
        setFormData({
            department: budget.department,
            amount: budget.amount,
            currency: budget.currency || 'USD',
            fiscalYear: budget.fiscalYear
        });
        setShowModal(true);
    };

    const handleCreate = () => {
        setEditingId(null);
        setFormData({ department: 'General', amount: 0, currency: 'USD', fiscalYear: '2026' });
        setShowModal(true);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            if (editingId) {
                await updateBudget(editingId, {
                    department: formData.department,
                    amount: formData.amount,
                    currency: formData.currency,
                    fiscalYear: formData.fiscalYear
                });
            } else {
                await createBudget({
                    department: formData.department,
                    amount: formData.amount,
                    currency: formData.currency,
                    fiscalYear: formData.fiscalYear
                });
            }
            setShowModal(false);
            setFormData({ department: 'General', amount: 0, currency: 'USD', fiscalYear: '2026' });
            fetchData();
        } catch (error) {
            alert("Error saving budget");
        }
    };

    const getProgressColor = (percent: number) => {
        if (percent > 100) return 'var(--error)';
        if (percent > 80) return '#eab308'; // Warning/Yellow
        return 'var(--success)';
    };

    if (loading) return <div>Loading Budgets...</div>;

    return (
        <div>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                <h1 style={{ fontSize: '1.875rem', fontWeight: 'bold', color: 'var(--primary)' }}>Budget Management</h1>
                <button className="btn btn-primary" onClick={handleCreate}>+ Set Budget</button>
            </div>

            {showModal && (
                <div style={{ position: 'fixed', inset: 0, backgroundColor: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 50 }}>
                    <div className="card" style={{ width: '450px', maxWidth: '90%' }}>
                        <h2 style={{ fontSize: '1.25rem', fontWeight: 'bold', marginBottom: '1rem' }}>
                            {editingId ? 'Edit Budget' : 'Set Department Budget'}
                        </h2>
                        <form onSubmit={handleSubmit}>
                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1rem' }}>
                                <div>
                                    <label style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.875rem' }}>Fiscal Year</label>
                                    <input type="text" readOnly value="2026" style={{ width: '100%', padding: '0.5rem', backgroundColor: '#f3f4f6', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }} />
                                </div>
                                <div>
                                    <label style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.875rem' }}>Department</label>
                                    <select style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}
                                        value={formData.department} onChange={e => setFormData({ ...formData, department: e.target.value })}>
                                        <option value="General">General</option>
                                        <option value="IT">IT</option>
                                        <option value="Marketing">Marketing</option>
                                        <option value="Operations">Operations</option>
                                        <option value="Finance">Finance</option>
                                        <option value="HR">HR</option>
                                    </select>
                                </div>
                            </div>

                            <div style={{ marginBottom: '1rem' }}>
                                <label style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.875rem' }}>Currency</label>
                                <select style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}
                                    value={formData.currency} onChange={e => setFormData({ ...formData, currency: e.target.value })}>
                                    {CURRENCIES.map(c => (
                                        <option key={c.code} value={c.code}>{c.flag} {c.country} - {c.name}</option>
                                    ))}
                                </select>
                            </div>

                            <div style={{ marginBottom: '1.5rem' }}>
                                <label style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.875rem' }}>Budget Limit</label>
                                <input type="number" step="1000" required style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}
                                    value={formData.amount} onChange={e => setFormData({ ...formData, amount: Number(e.target.value) })} />
                            </div>

                            <div style={{ display: 'flex', gap: '1rem', justifyContent: 'flex-end' }}>
                                <button type="button" className="btn" onClick={() => setShowModal(false)}>Cancel</button>
                                <button type="submit" className="btn btn-primary">Save Budget</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: '1.5rem' }}>
                {budgets.map(budget => {
                    const spent = spendByDept[budget.department] || 0;
                    const percent = (spent / budget.amount) * 100;
                    const currency = budget.currency || 'USD';

                    return (
                        <div key={budget.id} className="card">
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1rem' }}>
                                <div>
                                    <h3 style={{ fontWeight: 'bold', fontSize: '1.1rem' }}>{budget.department}</h3>
                                    <span style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>FY {budget.fiscalYear}</span>
                                </div>
                                <div style={{ textAlign: 'right' }}>
                                    <div style={{ fontWeight: 'bold', fontSize: '1.1rem' }}>{formatCurrency(budget.amount, currency)}</div>
                                    <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>Limit</div>
                                </div>
                            </div>

                            <div style={{ marginBottom: '0.5rem' }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.875rem', marginBottom: '0.25rem' }}>
                                    <span style={{ color: percent > 100 ? 'var(--error)' : 'var(--text-primary)' }}>
                                        {formatCurrency(spent, currency)} Spent
                                    </span>
                                    <span style={{ fontWeight: 600 }}>{percent.toFixed(1)}%</span>
                                </div>
                                <div style={{ height: '8px', width: '100%', backgroundColor: '#f1f5f9', borderRadius: '4px', overflow: 'hidden' }}>
                                    <div style={{
                                        height: '100%',
                                        width: `${Math.min(percent, 100)}%`,
                                        backgroundColor: getProgressColor(percent),
                                        borderRadius: '4px'
                                    }} />
                                </div>
                            </div>

                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '1rem' }}>
                                <div style={{ fontSize: '0.75rem', color: 'var(--error)' }}>
                                    {percent > 90 && "⚠️ Budget critical"}
                                </div>
                                <button
                                    onClick={() => handleEdit(budget)}
                                    style={{ fontSize: '0.875rem', color: 'var(--accent)', textDecoration: 'underline', background: 'none', border: 'none', cursor: 'pointer' }}
                                >
                                    Edit Check
                                </button>
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
}
